import React from "react";

function Hero({ setPage }) {
  return (
    <section className="hero-section">
      <div className="hero-overlay" />
      <div className="hero-content container">
        <p className="hero-kicker">Smart Drainage Monitoring System</p>
        <h1>Monitor. Predict. Prevent Urban Flooding.</h1>
        <p className="hero-text">
          UrbanDrainX uses real-time sensor intelligence to track water levels,
          detect blockages, and help city teams act before drainage failures become
          disasters.
        </p>
        <button className="cta-btn" onClick={() => setPage("login")}>
          Access Dashboard
        </button>
      </div>
    </section>
  );
}

export default Hero;
